mapper.select:
select * from wh_work_hour
where del_flag = '0'
and wh_no like concat('%', #{whNo}, '%')
and proj_id = #{projId}
and node_id = #{nodeId}
and work_type = #{workType}
and status = #{status}
and work_date >= #{beginWorkDate}
and work_date <= #{endWorkDate}
order by create_time desc, wh_id desc

mapper.update:
update wh_work_hour
set wh_no=#{whNo}, proj_id=#{projId}, proj_name=#{projName}, node_id=#{nodeId}, node_name=#{nodeName}, category_id=#{categoryId}, category_name=#{categoryName}, work_type=#{workType}, work_date=#{workDate}, work_hours=#{workHours}, unit_price=#{unitPrice}, work_cost=#{workCost}, work_desc=#{workDesc}, status=#{status}, submit_time=#{submitTime}, approve_by=#{approveBy}, approve_time=#{approveTime}, reject_reason=#{rejectReason}, update_by=#{updateBy}, update_time=now(), remark=#{remark}
where wh_id=#{whId}
